def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start = None
    for num in nums:
        if num > 1 and (start is None or num != start + 1):
            if start is not None:
                result.append(f'{start}-{num - 1}' if start != num else str(start))
            start = num
        elif num == start + 1:
            continue
    if start is not None:
        result.append(str(start) if start == num else f'{start}-{num}')
    return ','.join(result)
